import { jest } from '@jest/globals';
import FileModifier from '../src/modifier/FileModifier.js';
import fs from 'fs/promises';
import os from 'os';
import path from 'path';

// Mock fs module
jest.mock('fs/promises');

describe('FileModifier', () => {
  let fileModifier;
  let mockFileSystemManager;
  let tempDir;

  beforeEach(() => {
    // Use a temp directory for tests
    tempDir = path.join(os.tmpdir(), 'filemodifier-test');

    // Create mock FileSystemManager
    mockFileSystemManager = {
      rootPath: tempDir,
      readFile: jest.fn(),
      writeFile: jest.fn(),
      exists: jest.fn(),
      getStats: jest.fn(),
      isBinary: jest.fn(),
      validatePath: jest.fn((path) => path)
    };

    // Mock fs operations
    fs.mkdir = jest.fn().mockResolvedValue();
    fs.writeFile = jest.fn().mockResolvedValue();
    fs.unlink = jest.fn().mockResolvedValue();

    fileModifier = new FileModifier(mockFileSystemManager);
  });

  describe('generateDiff', () => {
    it('should generate diff for simple text change', () => {
      const original = 'Hello World';
      const modified = 'Hello JavaScript World';

      const result = fileModifier.generateDiff(original, modified);

      expect(result).toHaveProperty('patches');
      expect(result).toHaveProperty('structuredDiff');
      expect(result).toHaveProperty('statistics');
      expect(result.statistics.additions).toBeGreaterThan(0);
      expect(result.statistics.deletions).toBeGreaterThan(0);
    });

    it('should generate diff for multi-line changes', () => {
      const original = 'line1\nline2\nline3';
      const modified = 'line1\nmodified line2\nline3\nline4';

      const result = fileModifier.generateDiff(original, modified);

      expect(result.statistics.additions).toBeGreaterThan(0);
      expect(result.statistics.deletions).toBeGreaterThan(0);
      expect(result.statistics.total).toBeGreaterThan(0);
    });

    it('should handle empty original content', () => {
      const original = '';
      const modified = 'new content';

      const result = fileModifier.generateDiff(original, modified);

      expect(result.statistics.additions).toBe(1);
      expect(result.statistics.deletions).toBe(0);
    });

    it('should handle empty modified content', () => {
      const original = 'old content';
      const modified = '';

      const result = fileModifier.generateDiff(original, modified);

      expect(result.statistics.additions).toBe(0);
      expect(result.statistics.deletions).toBe(1);
    });

    it('should respect ignoreWhitespace option', () => {
      const original = 'line1\nline2';
      const modified = 'line1  \nline2';

      const resultWithWhitespace = fileModifier.generateDiff(original, modified, { ignoreWhitespace: false });
      const resultIgnoreWhitespace = fileModifier.generateDiff(original, modified, { ignoreWhitespace: true });

      expect(resultWithWhitespace.statistics.additions + resultWithWhitespace.statistics.deletions).toBeGreaterThan(0);
      expect(resultIgnoreWhitespace.statistics.additions + resultIgnoreWhitespace.statistics.deletions).toBe(0);
    });

    it('should use custom context lines', () => {
      const original = 'line1\nline2\nline3\nline4\nline5';
      const modified = 'line1\nline2\nmodified\nline4\nline5';

      const result = fileModifier.generateDiff(original, modified, { context: 1 });

      expect(result.patches).toContain('modified');
    });
  });

  describe('previewChanges', () => {
    it('should preview changes for existing file', async () => {
      const filePath = 'test.js';
      const originalContent = 'const x = 1;';
      const newContent = 'const x = 2;';

      mockFileSystemManager.readFile.mockResolvedValue(originalContent);

      const result = await fileModifier.previewChanges({
        filePath,
        newContent
      });

      expect(result.previews).toHaveLength(1);
      expect(result.previews[0].filePath).toBe(filePath);
      expect(result.previews[0].fileExists).toBe(true);
      expect(result.previews[0].diff.statistics.additions).toBeGreaterThan(0);
      expect(result.summary.filesModified).toBe(1);
      expect(result.summary.filesUpdated).toBe(1);
    });

    it('should preview changes for new file', async () => {
      const filePath = 'new.js';
      const newContent = 'const x = 1;';

      mockFileSystemManager.readFile.mockRejectedValue(new Error('File not found: new.js'));

      const result = await fileModifier.previewChanges({
        filePath,
        newContent
      });

      expect(result.previews).toHaveLength(1);
      expect(result.previews[0].fileExists).toBe(false);
      expect(result.summary.filesCreated).toBe(1);
    });

    it('should preview changes for multiple files', async () => {
      mockFileSystemManager.readFile
        .mockResolvedValueOnce('old content 1')
        .mockResolvedValueOnce('old content 2');

      const modifications = [
        { filePath: 'file1.js', newContent: 'new content 1' },
        { filePath: 'file2.js', newContent: 'new content 2' }
      ];

      const result = await fileModifier.previewChanges(modifications);

      expect(result.previews).toHaveLength(2);
      expect(result.summary.filesModified).toBe(2);
      expect(mockFileSystemManager.readFile).toHaveBeenCalledTimes(2);
    });

    it('should handle single modification object', async () => {
      mockFileSystemManager.readFile.mockResolvedValue('old');

      const result = await fileModifier.previewChanges({
        filePath: 'test.js',
        newContent: 'new'
      });

      expect(result.previews).toHaveLength(1);
    });

    it('should throw error for invalid modification', async () => {
      await expect(
        fileModifier.previewChanges({ filePath: 'test.js' })
      ).rejects.toThrow('Modification must include filePath and newContent');
    });

    it('should calculate correct summary statistics', async () => {
      mockFileSystemManager.readFile
        .mockResolvedValueOnce('line1\nline2')
        .mockRejectedValueOnce(new Error('File not found'));

      const modifications = [
        { filePath: 'existing.js', newContent: 'line1\nline2\nline3' },
        { filePath: 'new.js', newContent: 'content' }
      ];

      const result = await fileModifier.previewChanges(modifications);

      expect(result.summary.filesModified).toBe(2);
      expect(result.summary.filesCreated).toBe(1);
      expect(result.summary.filesUpdated).toBe(1);
      expect(result.summary.totalAdditions).toBeGreaterThan(0);
    });
  });

  describe('validateChanges', () => {
    it('should validate correct modifications', async () => {
      mockFileSystemManager.exists.mockResolvedValue(true);
      mockFileSystemManager.getStats.mockResolvedValue({ isDirectory: false });
      mockFileSystemManager.isBinary.mockResolvedValue(false);

      const result = await fileModifier.validateChanges({
        filePath: 'test.js',
        newContent: 'const x = 1;'
      });

      expect(result.valid).toBe(true);
      expect(result.errors).toHaveLength(0);
    });

    it('should detect missing filePath', async () => {
      const result = await fileModifier.validateChanges({
        newContent: 'content'
      });

      expect(result.valid).toBe(false);
      expect(result.errors).toHaveLength(1);
      expect(result.errors[0].error).toContain('Missing filePath');
    });

    it('should detect missing newContent', async () => {
      const result = await fileModifier.validateChanges({
        filePath: 'test.js'
      });

      expect(result.valid).toBe(false);
      expect(result.errors).toHaveLength(1);
      expect(result.errors[0].error).toContain('Missing newContent');
    });

    it('should detect invalid path', async () => {
      mockFileSystemManager.validatePath.mockImplementation(() => {
        throw new Error('Invalid path');
      });

      const result = await fileModifier.validateChanges({
        filePath: '../../../etc/passwd',
        newContent: 'content'
      });

      expect(result.valid).toBe(false);
      expect(result.errors[0].error).toContain('Invalid path');
    });

    it('should detect directory instead of file', async () => {
      mockFileSystemManager.exists.mockResolvedValue(true);
      mockFileSystemManager.getStats.mockResolvedValue({ isDirectory: true });

      const result = await fileModifier.validateChanges({
        filePath: 'src',
        newContent: 'content'
      });

      expect(result.valid).toBe(false);
      expect(result.errors[0].error).toContain('directory');
    });

    it('should warn about binary files', async () => {
      mockFileSystemManager.exists.mockResolvedValue(true);
      mockFileSystemManager.getStats.mockResolvedValue({ isDirectory: false });
      mockFileSystemManager.isBinary.mockResolvedValue(true);

      const result = await fileModifier.validateChanges({
        filePath: 'image.png',
        newContent: 'binary content'
      });

      expect(result.valid).toBe(true);
      expect(result.warnings).toHaveLength(1);
      expect(result.warnings[0].warning).toContain('binary');
    });

    it('should warn about large files', async () => {
      mockFileSystemManager.exists.mockResolvedValue(false);

      const largeContent = 'x'.repeat(11 * 1024 * 1024); // 11MB

      const result = await fileModifier.validateChanges({
        filePath: 'large.js',
        newContent: largeContent
      });

      expect(result.valid).toBe(true);
      expect(result.warnings.some(w => w.warning.includes('10MB'))).toBe(true);
    });

    it('should warn about dangerous patterns', async () => {
      mockFileSystemManager.exists.mockResolvedValue(false);

      const result = await fileModifier.validateChanges({
        filePath: 'dangerous.sh',
        newContent: 'rm -rf /'
      });

      expect(result.valid).toBe(true);
      expect(result.warnings.some(w => w.warning.includes('dangerous'))).toBe(true);
    });

    it('should validate multiple modifications', async () => {
      mockFileSystemManager.exists.mockResolvedValue(true);
      mockFileSystemManager.getStats.mockResolvedValue({ isDirectory: false });
      mockFileSystemManager.isBinary.mockResolvedValue(false);

      const modifications = [
        { filePath: 'file1.js', newContent: 'content1' },
        { filePath: 'file2.js', newContent: 'content2' },
        { newContent: 'no path' } // Invalid
      ];

      const result = await fileModifier.validateChanges(modifications);

      expect(result.valid).toBe(false);
      expect(result.errors).toHaveLength(1);
    });

    it('should handle validation for new files', async () => {
      mockFileSystemManager.exists.mockResolvedValue(false);

      const result = await fileModifier.validateChanges({
        filePath: 'new.js',
        newContent: 'const x = 1;'
      });

      expect(result.valid).toBe(true);
      expect(result.errors).toHaveLength(0);
    });
  });

  describe('createBackup', () => {
    it('should create backup for existing file', async () => {
      const filePath = 'test.js';
      const content = 'original content';

      mockFileSystemManager.exists.mockResolvedValue(true);
      mockFileSystemManager.readFile.mockResolvedValue(content);

      const backupPath = await fileModifier.createBackup(filePath);

      expect(backupPath).toBeTruthy();
      expect(backupPath).toContain('.backup');
      expect(mockFileSystemManager.readFile).toHaveBeenCalledWith(filePath);
    });

    it('should return null for non-existent file', async () => {
      mockFileSystemManager.exists.mockResolvedValue(false);

      const backupPath = await fileModifier.createBackup('new.js');

      expect(backupPath).toBeNull();
    });

    it('should store backup information', async () => {
      const filePath = 'test.js';
      const content = 'original content';

      mockFileSystemManager.exists.mockResolvedValue(true);
      mockFileSystemManager.readFile.mockResolvedValue(content);

      await fileModifier.createBackup(filePath);

      const backups = fileModifier.getBackups();
      expect(backups).toHaveLength(1);
      expect(backups[0].filePath).toBe(filePath);
    });
  });

  describe('applyChanges', () => {
    it('should apply changes to single file', async () => {
      mockFileSystemManager.exists.mockResolvedValue(true);
      mockFileSystemManager.readFile.mockResolvedValue('old content');
      mockFileSystemManager.getStats.mockResolvedValue({ isDirectory: false });
      mockFileSystemManager.isBinary.mockResolvedValue(false);
      mockFileSystemManager.writeFile.mockResolvedValue();

      const result = await fileModifier.applyChanges({
        filePath: 'test.js',
        newContent: 'new content'
      }, true);

      expect(result.success).toBe(true);
      expect(result.filesModified).toBe(1);
      expect(mockFileSystemManager.writeFile).toHaveBeenCalledWith('test.js', 'new content');
    });

    it('should apply changes to multiple files', async () => {
      mockFileSystemManager.exists.mockResolvedValue(true);
      mockFileSystemManager.readFile.mockResolvedValue('old content');
      mockFileSystemManager.getStats.mockResolvedValue({ isDirectory: false });
      mockFileSystemManager.isBinary.mockResolvedValue(false);
      mockFileSystemManager.writeFile.mockResolvedValue();

      const modifications = [
        { filePath: 'file1.js', newContent: 'content1' },
        { filePath: 'file2.js', newContent: 'content2' }
      ];

      const result = await fileModifier.applyChanges(modifications, true);

      expect(result.success).toBe(true);
      expect(result.filesModified).toBe(2);
      expect(mockFileSystemManager.writeFile).toHaveBeenCalledTimes(2);
    });

    it('should create backups before applying changes', async () => {
      mockFileSystemManager.exists.mockResolvedValue(true);
      mockFileSystemManager.readFile.mockResolvedValue('old content');
      mockFileSystemManager.getStats.mockResolvedValue({ isDirectory: false });
      mockFileSystemManager.isBinary.mockResolvedValue(false);
      mockFileSystemManager.writeFile.mockResolvedValue();

      const result = await fileModifier.applyChanges({
        filePath: 'test.js',
        newContent: 'new content'
      }, true);

      expect(result.backups).toHaveLength(1);
      expect(result.backups[0].filePath).toBe('test.js');
    });

    it('should handle new files without backup', async () => {
      mockFileSystemManager.exists.mockResolvedValue(false);
      mockFileSystemManager.writeFile.mockResolvedValue();

      const result = await fileModifier.applyChanges({
        filePath: 'new.js',
        newContent: 'content'
      }, true);

      expect(result.success).toBe(true);
      expect(result.filesModified).toBe(1);
    });

    it('should fail validation for invalid changes', async () => {
      await expect(
        fileModifier.applyChanges({
          filePath: 'test.js'
          // Missing newContent
        }, true)
      ).rejects.toThrow('Validation failed');
    });

    it('should request confirmation when not confirmed', async () => {
      mockFileSystemManager.exists.mockResolvedValue(false);
      mockFileSystemManager.writeFile.mockResolvedValue();

      const confirmCallback = jest.fn().mockResolvedValue(true);

      const result = await fileModifier.applyChanges({
        filePath: 'test.js',
        newContent: 'content'
      }, false, confirmCallback);

      expect(confirmCallback).toHaveBeenCalled();
      expect(result.success).toBe(true);
    });

    it('should cancel when user denies confirmation', async () => {
      mockFileSystemManager.exists.mockResolvedValue(false);

      const confirmCallback = jest.fn().mockResolvedValue(false);

      const result = await fileModifier.applyChanges({
        filePath: 'test.js',
        newContent: 'content'
      }, false, confirmCallback);

      expect(result.success).toBe(false);
      expect(result.message).toContain('cancelled');
      expect(mockFileSystemManager.writeFile).not.toHaveBeenCalled();
    });

    it('should rollback on failure', async () => {
      mockFileSystemManager.exists.mockResolvedValue(true);
      mockFileSystemManager.readFile.mockResolvedValue('old content');
      mockFileSystemManager.getStats.mockResolvedValue({ isDirectory: false });
      mockFileSystemManager.isBinary.mockResolvedValue(false);
      mockFileSystemManager.writeFile
        .mockResolvedValueOnce() // First file succeeds
        .mockRejectedValueOnce(new Error('Write failed')); // Second file fails

      const modifications = [
        { filePath: 'file1.js', newContent: 'content1' },
        { filePath: 'file2.js', newContent: 'content2' }
      ];

      const result = await fileModifier.applyChanges(modifications, true);

      expect(result.success).toBe(false);
      expect(result.filesModified).toBe(0);
    });
  });

  describe('rollback', () => {
    beforeEach(async () => {
      // Setup a backup
      mockFileSystemManager.exists.mockResolvedValue(true);
      mockFileSystemManager.readFile.mockResolvedValue('original content');
      await fileModifier.createBackup('test.js');
    });

    it('should rollback single file', async () => {
      mockFileSystemManager.writeFile.mockResolvedValue();

      const result = await fileModifier.rollback('test.js');

      expect(result.success).toBe(true);
      expect(result.filesRolledBack).toBe(1);
      expect(mockFileSystemManager.writeFile).toHaveBeenCalledWith('test.js', 'original content');
    });

    it('should rollback multiple files', async () => {
      // Create another backup
      mockFileSystemManager.readFile.mockResolvedValue('original content 2');
      await fileModifier.createBackup('test2.js');

      mockFileSystemManager.writeFile.mockResolvedValue();

      const result = await fileModifier.rollback(['test.js', 'test2.js']);

      expect(result.success).toBe(true);
      expect(result.filesRolledBack).toBe(2);
    });

    it('should handle missing backup', async () => {
      const result = await fileModifier.rollback('nonexistent.js');

      expect(result.success).toBe(false);
      expect(result.filesRolledBack).toBe(0);
      expect(result.results[0].error).toContain('No backup found');
    });

    it('should clear backup after successful rollback', async () => {
      mockFileSystemManager.writeFile.mockResolvedValue();

      await fileModifier.rollback('test.js');

      const backups = fileModifier.getBackups();
      expect(backups).toHaveLength(0);
    });

    it('should handle rollback failure', async () => {
      mockFileSystemManager.writeFile.mockRejectedValue(new Error('Write failed'));

      const result = await fileModifier.rollback('test.js');

      expect(result.success).toBe(false);
      expect(result.results[0].success).toBe(false);
    });
  });

  describe('getBackups', () => {
    it('should return empty array when no backups', () => {
      const backups = fileModifier.getBackups();
      expect(backups).toEqual([]);
    });

    it('should return list of backups', async () => {
      mockFileSystemManager.exists.mockResolvedValue(true);
      mockFileSystemManager.readFile.mockResolvedValue('content');

      await fileModifier.createBackup('file1.js');
      await fileModifier.createBackup('file2.js');

      const backups = fileModifier.getBackups();
      expect(backups).toHaveLength(2);
      expect(backups[0]).toHaveProperty('filePath');
      expect(backups[0]).toHaveProperty('backupPath');
      expect(backups[0]).toHaveProperty('timestamp');
      expect(backups[0]).toHaveProperty('date');
    });
  });

  describe('clearBackups', () => {
    it('should clear all backup information', async () => {
      mockFileSystemManager.exists.mockResolvedValue(true);
      mockFileSystemManager.readFile.mockResolvedValue('content');

      await fileModifier.createBackup('test.js');
      expect(fileModifier.getBackups()).toHaveLength(1);

      fileModifier.clearBackups();
      expect(fileModifier.getBackups()).toHaveLength(0);
    });
  });
});
